// Week number within 5th grade at which Buggsy crosses from two_bee
// to three_bee as his primary tier. Slide if the Nance calendar changes.
var FIFTH_GRADE_CROSSOVER_WEEK = 19;

function _tierForGradeAndWeek_(grade, weekNumber) {
  var g = parseInt(grade, 10) || 4;
  var w = parseInt(weekNumber, 10) || 1;
  if (g <= 3) return 'one_bee';
  if (g === 4) return 'two_bee';
  if (g === 5) {
    return w >= FIFTH_GRADE_CROSSOVER_WEEK ? 'three_bee' : 'two_bee';
  }
  return 'three_bee';
}

function _weekIntroducedFromIndex_(idx, tier) {
  var list = SPELLING_CATALOG[tier] || [];
  if (list.length === 0) return 0;
  return Math.floor((idx % list.length) / 5) + 1;
}

function _annotate_(entry, tier, weekIntroduced) {
  return {
    word: entry.word,
    definition: entry.definition,
    kid_definition: entry.kid_definition || entry.definition,
    sentence: entry.sentence || '',
    part_of_speech: entry.part_of_speech || '',
    pronunciation: entry.pronunciation || '',
    origin: entry.origin || '',
    tier: tier,
    weekIntroduced: weekIntroduced
  };
}

function getSpellingWords_(grade, weekNumber) {
  var g = parseInt(grade, 10) || 4;
  var w = parseInt(weekNumber, 10) || 1;
  var tier = _tierForGradeAndWeek_(g, w);
  var list = SPELLING_CATALOG[tier] || [];
  if (list.length === 0) {
    return { grade: g, week: w, tierUsed: tier, newWords: [], reviewWords: [], allWords: [], version: getSpellingCatalogVersion() };
  }
  var newStart = ((w - 1) * 5) % list.length;
  var newWords = [];
  for (var i = 0; i < 5; i++) {
    var idx = (newStart + i) % list.length;
    newWords.push(_annotate_(list[idx], tier, _weekIntroducedFromIndex_(idx, tier)));
  }
  var reviewWords = [];
  if (w > 1) {
    for (var j = 1; j <= 3; j++) {
      var lookback = w - j;
      if (lookback < 1) break;
      var lookbackTier = _tierForGradeAndWeek_(g, lookback);
      var lookbackList = SPELLING_CATALOG[lookbackTier] || [];
      if (lookbackList.length === 0) continue;
      var lbStart = ((lookback - 1) * 5) % lookbackList.length;
      var lbIdx = (lbStart + (j % 5)) % lookbackList.length;
      reviewWords.push(_annotate_(lookbackList[lbIdx], lookbackTier, lookback));
    }
  }
  return {
    grade: g,
    week: w,
    tierUsed: tier,
    newWords: newWords,
    reviewWords: reviewWords,
    allWords: newWords.concat(reviewWords),
    version: getSpellingCatalogVersion()
  };
}

function getSpellingWordsSafe(grade, weekNumber) {
  if (typeof withMonitor_ === 'function') {
    return withMonitor_('getSpellingWordsSafe', function() {
      return JSON.parse(JSON.stringify(getSpellingWords_(grade, weekNumber)));
    });
  }
  return JSON.parse(JSON.stringify(getSpellingWords_(grade, weekNumber)));
}

